function ModelPet:InitPet()
	for i, cfg in pairs(GameTable.MagicPetRef or {}) do
		local pet = StructPet:New(cfg)
		self.petList[cfg.refId] = pet
	end

	for _, cfg in pairs(GameTable.MagicPetStarRef or {}) do
		if not self.petStarCfg[cfg.type] then self.petStarCfg[cfg.type] = {} end
		self.petStarCfg[cfg.type][cfg.rankNow] = cfg
	end

end

