function ModelPet:OnPetListResp(pb)
	self.heroLinkPets = {}
	for i,v in ipairs(pb.datas or {}) do--宠物
		self:OnUpdatePetByPb(v)
	end
	for i,v in ipairs(pb.relationObj.refId or {}) do
		self.petRelation[v] = v
	end
	---@type StructPetEquip
	for i ,v in ipairs(pb.equipInfos or {}) do--宠物装备
		self:CreatePetEquipByPb(v)
	end
	
	self:OnUpdateAttrByPb(pb.petAttr,pb.relationAttr)
	FireEvent(EventNames.PET_LIST_UPATE)
end

function ModelPet:OnPetUpSatrResp(pb)
	local isActive=self:GetPetById(pb.petObj.petRefId).isActive
	self:OnUpdatePetByPb(pb.petObj)
	local isActive = not isActive
	GF.OpenWnd("UIPeActiSuccess",{refId = pb.petObj.petRefId,isActive = isActive})
	FireEvent(EventNames.PET_CHANGE_STAR,isActive )
end

function ModelPet:OnPetUpLevelResp(pb)
	local pet = self.petList[pb.petObj.petRefId]
	local oldLv = pet._level
	self:OnUpdatePetByPb(pb.petObj)
	FireEvent(EventNames.PET_CHANGE_LEVEL)
	if oldLv~=pet._level then 
		-- GF.ShowMessage(ccClientText(10018))
		local oldAttr = pet:GetLvCfg(oldLv).attr
		local oldAttrMap = LUtil.ConvertCommonAttrStrToMap(oldAttr)
		local newAttr = pet:GetLvAttr()
		local addAttr = {}
		for _, attr in ipairs(newAttr) do
			if oldAttrMap[attr.refId][attr.type] then attr.value = attr.value-oldAttrMap[attr.refId][attr.type] end
			table.insert(addAttr,{refId = attr.refId,addNum = attr.value,type = attr.type})
		end
		
		GF.CloseWndByName("UISagaPowerTips")
		GF.OpenWndDebug("UISagaPowerTips", { dataList = addAttr})
	end
	
end

function ModelPet:OnPetAttrUpdateResp(pb)
