end

function ModelPet:OnPetLinkResp(pb)
	---@type StructPet
	local pet = self:GetPetById(pb.petId)
	pet:SetPetLink(pb.heroId,pb.petId)
	for _, change in ipairs(pb.petChange) do--被替换的宠物英雄
		if self.heroLinkPets[change.heroId] and self.heroLinkPets[change.heroId][change.petId] then 
			self.heroLinkPets[change.heroId][change.petId] = nil
		end
		local pet = gModelPet:GetPetById(change.petId)
		pet:RemoveLinkHeroById(change.heroId)
	end
	GF.ShowMessage(ccClientText(43751))
	FireEvent(EventNames.PET_CHANGE_LINK)
end
