function ModelPet:OnPetEquipChangeResp(pb)
	for i, change in ipairs(pb.change or {}) do
		if change.syncType ==1 then--增加
			self:CreatePetEquipByPb(change.equip)
		elseif change.syncType==2 and change.equip.petRefId then--删除
			self.petList[change.equip.petRefId] = nil
		elseif change.syncType==3 then--更新
			self:CreatePetEquipByPb(change.equip)
		end
	end
	FireEvent(EventNames.PET_EQUIP_CHANGE)
end

function ModelPet:OnPetLinkByHeroResp(pb)
