		self:OnUpdatePetByPb(pet)
	end
	if pb.type==2 then 
		GF.ShowMessage(ccClientText(24848))
	else
		GF.ShowMessage(ccClientText(43751))
	end
	FireEvent(EventNames.PET_CHANGE_LINK)
end

function ModelPet:OnUpdatePetByPb(pb)
	if not pb then return end
	---@type StructPet
	local pet = self.petList[pb.petRefId]
	if not pet then
		pet = StructPet:New()
		self.petList[pb.petRefId] = pet
	end
	pet:CreateByPb(pb)
end
function ModelPet:CreatePetEquipByPb(pb)
	if not pb then return end
	---@type StructPetEquip
	local petEquip = self.equipList[pb.refId]
	if not petEquip then
		petEquip = StructPetEquip.NewStructPetEquip()
		self.equipList[pb.refId] = petEquip
	end
	petEquip:CreateByPb(pb)
end

