function ModelPet:GetTotalStar()
	local star = 0
	for _, pet in pairs(self.petList) do
		if pet.isActive then 
			star = star+pet._star
		end
	end
	return star
end

function ModelPet:GetHeroMaxLinkNum()
	local totalStar = self:GetTotalStar()
	local refs = GameTable.MagicPetStarHeroNumRef
	local curRef = 0
	for _, value in ipairs(refs) do
		if value.num<=totalStar then 
			curRef = value.refId
		else
			break
		end
	end
	return curRef
end

function ModelPet:CheckCost(costStr,showTips)
    local costList = LxDataHelper.ParseItem(costStr)-- LUtil.GetRefItemDataList(costStr)
    for i, v in ipairs(costList) do
        local haveNum = gModelItem:GetNumByRefId(v.itemId)
        local needNum = v.itemNum
        if haveNum < needNum then
            if showTips then
				local itemRef = GameTable.PlayerItemRef[v.itemId]
				if itemRef.jump ~= "" then
					local needNum_2 = needNum - haveNum
					gModelGeneral:OpenGetWayWnd({ itemId = itemRef.refId,needNum=needNum_2 })
				else
					local itemName = gModelItem:GetNameByRefId(v.itemId)
                	GF.ShowMessage(ccClientText(43761, itemName))
				end
            end
            return false
        end
    end
	return true
end
function ModelPet:GetStarPath(star)
	local index = math.ceil(star/5)
	local starPath = index==0 and "hero_icon_star1_1" or "hero_icon_star"..math.min(index,5)
	return starPath
end
function ModelPet:SetStar(TranStar,refId,star,callBack)
	-- 0星-返灰星 
	-- 1~5星用1开始
	-- 6~10用2开始
	-- 11~15用3开始
	-- 16~20用4开始
	-- 满星一定只用5
	local petInfo = self:GetPetById(refId)
	star = star or petInfo._star
	local starPath = self:GetStarPath(star)
	local num = (star>0 and star%5==0) and 5 or star%5
	local starCfg = petInfo:GetPetStarCfg(star)
	if starCfg.rankNext<=0 then
		starPath = "hero_icon_star5"
		TranStar.transform.sizeDelta = Vector2(88, 40);
	else
		TranStar.transform.sizeDelta = Vector2(40*num, 40);
	end
	if callBack then callBack(starPath) end
end

function ModelPet:GetLvConfig(quality,lv)
	if not self.petLvCfg[quality] then
		for i, v in pairs(GameTable.MagicPetLvRef) do
			if not self.petLvCfg[v.quality] then self.petLvCfg[v.quality] = {} end
			self.petLvCfg[v.quality][v.lvNow] = v
		end
	end
	if lv then
		return self.petLvCfg[quality][lv]
	else
		return self.petLvCfg[quality]
	end
end

