function ModelPet:GetEquipListByPart(part)
	local equipList = self:GetPetEquipList()
	local list = {}
	for _, v in pairs(equipList) do
		if self:GetPetEquipRef(v._refId).type == part and v._score > 0 then
			table.insert(list, v)
		end
	end
	return list
end

function ModelPet:GetPetIconByRefId(refId)
    local icon, iconBg
    local ref = self:GetPetEquipRef(refId)
    if ref then
        icon = ref.icon
        local quality = ref.quality
        iconBg = gModelItem:GetIconBgByQualityId(quality)
    end
    return icon, iconBg
end

