function ModelPet:GetTotalAttr()
	local totalAttrStr = ""
	for k , pet in pairs(self.petList) do
		if pet.isActive then
			local petTotalAttr = pet:GetTotalAttrStr()
			if not string.isempty(petTotalAttr) then
				totalAttrStr =  petTotalAttr..","..totalAttrStr
			end
		end
	end
	totalAttrStr = string.sub(totalAttrStr,1,#totalAttrStr-1)
	local totalAttrMap = LUtil.ConvertCommonAttrStrToMap(totalAttrStr)
	local attrs = LUtil.MapAttrToListAttr(totalAttrMap)
	return attrs
end

function ModelPet:GetPetRelationAttr()
	local relationCfg = GameTable.MagicPetRelationRef
	local attrs = ""
	for _, value in pairs(self.petRelation) do
		if not string.isempty(relationCfg[value].attr) then 
			attrs = attrs..","..relationCfg[value].attr
		end
	end
	attrs = string.sub(attrs,2,#attrs)
	local totalAttrMap = LUtil.ConvertCommonAttrStrToMap(attrs)
	local attrs = LUtil.MapAttrToListAttr(totalAttrMap)
	return attrs
end

function ModelPet:GetTotalAttrAdd()
	local totalAttrAdd = 0
	---@type StructPet
	for _, pet in pairs(self.petList) do
		if pet.isActive then
			local petAttrAdd = pet:GetAttrChangeAdd()
			totalAttrAdd = totalAttrAdd+petAttrAdd
		end
	end
	return totalAttrAdd
end

