--英雄可连接的宠物列表
function ModelPet:GetCanLinkPetList(heroId)
	local petList = {}
	local curHeroLinkMaxNum = self:GetHeroMaxLinkNum()
	local heroSerData = gModelHero:GetHeroServerDataById(heroId)
	local curCount = #heroSerData.petIds
	for _, pet in pairs(self.petList) do
		if curCount < curHeroLinkMaxNum and pet:IsCanLinkHero(heroId) then 
			table.insert(petList,pet)
		end
	end
	return petList
end

function ModelPet:GetWearRedPointByPart(part)--装备红点
    local petEquips = self:GetPetEquipList()
	for _, v in pairs(petEquips) do
		if self:GetPetEquipRef(v._refId).type == part and v._num > 0 then
			return true
		end
	end
	return false
end
function ModelPet:GetStrongerEquipByPart(equip, part)--更高评分装备
    local petEquips = self:GetPetEquipList()
	for _, v in pairs(petEquips) do
		if self:GetPetEquipRef(v._refId).type == part then
			if v._score > equip._score and v._num > 0 then
				return v
			end
		end
	end
	return nil
end
---@return StructPetEquip
function ModelPet:GetStrongestEquipByPart(part)
	local petEquips = self:GetPetEquipList()
	local score, equip = 0, nil
	for _, v in pairs(petEquips) do
		if self:GetPetEquipRef(v._refId).type == part and v._num > 0 then
			if v._score > score then
				score = v._score
				equip = v
			end
		end
	end
	return equip
end


function ModelPet:GetResolveListToRwd(resolveList)
	local map = {}
	local petRefs = GameTable.MagicPetRef
	local itemRefs = GameTable.PlayerItemRef
	local petId = nil
    for _, v in ipairs(resolveList) do
		petId = tonumber(itemRefs[v.refId].typeDate)
		local petCfg  = petRefs[petId]
		if not self.petItemSell[petId] and not string.isempty(petCfg.itemSell) then 
			self.petItemSell[petId] = LUtil.GetRefItemDataList(petCfg.itemSell) 
		end
        local list = self.petItemSell[petId]
        for _, tab in ipairs(list or {}) do
            if not map[tab.refId] then
                map[tab.refId] = { refId = tab.refId, count = v.count * tab.count, type = tab.type }
            else
                map[tab.refId].count = map[tab.refId].count + v.count * tab.count
            end
        end
    end

    local list = {}
    for k, v in pairs(map) do
        v.itemId   = v.refId
        v.itemNum  = v.count
        v.itype    = v.type
        v.itemType = v.type
        table.insert(list, v)
    end
    return list
end

function ModelPet:CheckEquipCanCompound(refId)
	local cfg = self:GetPetEquipRef(refId)
	local compInfo = {
		maxCompNum = 0,
		costMoney = 0,
		costItem = 0,
		comConst = 0,
		needMoney = 0,
		needEquip = 0
	}
	local compound = cfg.compound
	if compound and compound ~= "" and cfg.composeOrder > 0 then
		local costItem, needMoney, comConst, needEquip
		local s = string.split(compound, ",")
		for i = 1, #s do
			local info = string.split(s[i], "=")
			if tonumber(info[1]) == 1 then
				costItem = tonumber(info[2])
				needMoney = tonumber(info[3])
			elseif tonumber(info[1]) == LItemTypeConst.TYPE_PET_EQUIP then
				needEquip = tonumber(info[2])
				comConst = tonumber(info[3])
			end
		end
		local needEquipCount = self.equipList[needEquip] and self.equipList[needEquip]._num or 0
		local temp = math.floor(needEquipCount / comConst)
		if costItem then
			local haveMoney = gModelItem:GetNumByRefId(costItem)
			local temp2 = math.floor(haveMoney / needMoney)
			compInfo.maxCompNum = math.min(temp, temp2)
		else
			compInfo.maxCompNum = temp
		end
		
		compInfo.costMoney = (needMoney or 0) * compInfo.maxCompNum
		compInfo.costItem = costItem
		compInfo.comConst = comConst
		compInfo.needMoney = needMoney or 0
		compInfo.needEquip = needEquip
	end
	return compInfo
end

function ModelPet:GetEquipCompoundRedPointByPart(part)
	for _, v in pairs(GameTable.MagicPetArticleRef) do
		if not part or v.type == part then
			local maxCompNum = self:CheckEquipCanCompound(v.refId).maxCompNum
			if maxCompNum > 0 then
				return true
			end
		end
	end
	return false
end
function ModelPet:GetPetEquipListByPart(part)
	local list = {}
	for _, v in pairs(GameTable.MagicPetArticleRef) do
		if v.type == part and not string.isempty(v.compound) and v.composeOrder > 0 then
			local equip = gModelPet:GetPetEquipByRefId(v.refId)
			if not equip then equip = StructPetEquip.NewStructPetEquip(v.refId) end
			table.insert(list, equip)
		end
	end
	return list
end
function ModelPet:CheckOneKeyAllCompund(part)
	---@type table<StructPetEquip>
	local lists = self:GetPetEquipListByPart(part)
	local compList = {}
	local compNeed = {}
	local hasEquip = false
	for _, item in ipairs(lists or {}) do
		local compInfo = self:CheckEquipCanCompound(item:GetRefId())
		if compInfo.maxCompNum >0 then 
			local petItem = StructPetEquip.NewStructPetEquip(item:GetRefId())
			petItem._num = compInfo.maxCompNum
			table.insert(compList,petItem)
			compNeed[item:GetRefId()] = {needRefId = compInfo.needEquip,needNum = compInfo.comConst*compInfo.maxCompNum}
			hasEquip = true
		end
	end
	return compList,compNeed,hasEquip
end


function ModelPet:PetLinkHeroRed()
	local dataList = gModelHero:GetHeroList()
    local starNeed = GameTable.MagicPetConfigRef.petHeroStar
	local hasNoLinkHero = false
	for _, value in pairs(dataList) do
		if value:GetStar()>=starNeed and #value.petIds==0 then --not value.petId
			hasNoLinkHero = true
			break
		end
	end
	if not hasNoLinkHero then return hasNoLinkHero end
	for _, value in pairs(self.petList) do
		if value.isActive then 
			local starCfgs = self.petStarCfg[value._petRefId]
			for _, value in pairs(starCfgs or {}) do
				if value.rankNow>value._star then return false end
				if value.link>0 and not value:GetPetLinkHeroId(value.link) then return true end
			end
		end
	end
	return false
end

function ModelPet:HeroLinkPetRedById(id,isCheckOpen)
	local heroSerData = gModelHero:GetHeroServerDataById(id)
    local linkStar = GameTable.MagicPetConfigRef.petHeroStar
	
	if not heroSerData then 
		printInfoN2("ModelPet","ModelPet == nil , id == "..id)
		return false
	end 
	
    if heroSerData.star < linkStar or gModelHero:GetHeroQualityById(heroSerData.id)<6 then return false end
    if not isCheckOpen then
    	if not gModelFunctionOpen:CheckIsOpened(21006000) then return false end
	end
    local list = self:GetCanLinkPetList(id)
    return #list>0
end

function ModelPet:HeroLinkPetRed()
	if not gModelFunctionOpen:CheckIsOpened(21006000) then return false end
	local heroList = gModelHero:GetHeroList()
	for _, hero in pairs(heroList) do
		if self:HeroLinkPetRedById(hero._id,true) then 
			return true
		end
	end
	return false
end

function ModelPet:PetRelationActiveRed()
	local cfgs = GameTable.MagicPetRelationRef
	for _, value in pairs(cfgs or {}) do
		local petlist = LxDataHelper.ParseIntParam_Comma(value.petId)
		local canActiva = true
		local pet = nil
		for _, id in ipairs(petlist) do
			pet = self:GetPetById(id)
			if not pet.isActive then 
				canActiva = false
				break 
			end
		end
		if canActiva then return canActiva end
	end
	return false
end

function ModelPet:PetListRedPoint()
	local allPet = GameTable.MagicPetRef
	---@type StructPet
	local petInfo = nil
	 for _, value in pairs(allPet) do
		petInfo = self:GetPetById(value.refId)
		if petInfo:IsCanUpLevel() or petInfo:IsCanUpStar() or petInfo:GetPetState()==2 then
			return true
		end
	 end
	 return false
end
function ModelPet:GetPetStarCfg(petId,star)
	if not petId then return end
	return self.petStarCfg[petId][star]
end
return ModelPet